import { Button } from '@universe-design/react';
import React from 'react';
import type { TreeSelectRef } from '..';
import { TreeSelect } from '..';
import type { TreeProps } from '../../tree/interface';

const getChildren = (prefix: string) =>
  // eslint-disable-next-line @typescript-eslint/no-magic-numbers
  new Array(20).fill('').map((_, index) => ({
    label: `${prefix}_child_${index}`,
    value: `${prefix}_${index}`,
  }));

export default () => {
  const ref = React.useRef<TreeSelectRef>(null);

  const treeData: TreeProps['treeData'] = [
    {
      label: 'Parent 1',
      value: '0-1',
      children: getChildren('1'),
    },
    {
      label: 'Parent 2',
      value: '0-2',
      children: getChildren('2'),
    },
  ];

  return (
    <>
      <Button id="trigger" onClick={() => ref.current?.scrollIntoView({ key: '1_10', type: 'node' }, { align: 'top' })}>
        {' '}
        Scroll To 1_10{' '}
      </Button>
      <TreeSelect
        className="admin-address-tree-select"
        style={{ width: '200px' }}
        treeData={treeData}
        showSearch={true}
        placeholder="请选择"
        ref={ref}
        virtual={false}
        open
      />
    </>
  );
};
